// Extrair dados do payload
const body = items[0].json.body || items[0].json;

// Construir URL da API Salesforce
const instanceUrl = body.sfInstanceUrl || '';
const apiUrl = instanceUrl + '/services/data/v58.0/sobjects/Lead';

// Construir headers com token
const tokenType = body.sfTokenType || 'Bearer';
const accessToken = body.sfAccessToken || '';

const headers = {
  'Authorization': tokenType + ' ' + accessToken,
  'Content-Type': 'application/json'
};

// Construir payload para Lead
const leadData = {
  FirstName: body.firstName || null,
  LastName: body.lastName || body.name || 'WhatsApp Lead',
  Company: body.name || body.company || body.lastName || 'N/A',
  Phone: body.phone || null,
  LeadSource: body.leadSource || 'WhatsApp',
  Description: body.description || '',
  Website: body.website || null,
  Industry: body.industry || null,
  Rating: body.rating || null,
  Apelido__c: body.apelido || 'BL' // Adicionando o campo Apelido__c
};

// Preparar item para próximo nó
items[0].json.sfUrl = apiUrl;
items[0].json.sfHeaders = headers;
items[0].json.sfLeadData = leadData;

return items;

// Capturar resposta do Salesforce (sucesso ou erro)
const item = items[0].json;
const statusCode = item.statusCode || item.status || null;
const id = item.id || null;

// Verificar se foi sucesso
const success = id !== null && id !== undefined;

let errorDetails = '';
let message = '';

if (success) {
  message = '✅ Lead criado com sucesso! ID: ' + id;
} else {
  // Extrair erro do Salesforce
  const sfErrors = item.body?.[0]?.message || item.message || item.error_description || 'Erro desconhecido';
  const fieldErrors = item.body?.[0]?.errorCode || item.errorCode || '';

  errorDetails = sfErrors;
  if (fieldErrors) {
    errorDetails = fieldErrors + ': ' + sfErrors;
  }

  // Mensagens customizadas por erro
  if (errorDetails.includes('INVALID_FIELD')) {
    message = '❌ Campo inválido ou não existe no Salesforce';
  } else if (errorDetails.includes('REQUIRED_FIELD_MISSING')) {
    message = '❌ Campo obrigatório faltando';
  } else if (errorDetails.includes('INVALID_CROSS_REFERENCE_KEY')) {
    message = '❌ Valor inválido em campo de referência';
  } else if (statusCode === 401 || errorDetails.includes('INVALID_AUTH')) {
    message = '❌ Token inválido ou expirado';
  } else if (statusCode === 403 || errorDetails.includes('ACCESS_DENIED')) {
    message = '❌ Sem permissão para criar Lead';
  } else {
    message = '❌ ' + errorDetails;
  }
}

return [{
  json: {
    success: success,
    leadId: id,
    message: message,
    statusCode: statusCode,
    errorDetails: errorDetails,
    errors: item.body || []
  }
}];
